import { type ReactNode } from 'react';

import type { MapShape } from '../types/shapes.js';

export const isValidShape = (shape: MapShape | ReactNode): shape is MapShape =>
  typeof shape === 'string' &&
  [
    'circle',
    'square',
    'diamond',
    'heart',
    'star',
    'cross',
    'triangle',
    'pin',
  ].includes(shape);
